1	const BASE_PREMIUMS: Record<string, number> = {
2	  sword: 100,
3	  amulet: 60,
4	  staff: 80,
5	};
6	
7	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
8	const PROCESSING_FEE = 5;
9	
10	const premiumForItem = (item: { type: string }): number => {
11	  const base = BASE_PREMIUMS[item.type];
12	  return base + base * FIRST_INSURANCE_SURCHARGE_RATE;
13	};
14	
15	export const runScenario = (scenario: any): unknown => {
16	  const items = scenario.steps[0].items;
17	  const itemsTotal = items.reduce(
18	    (sum: number, item: any) => sum + premiumForItem(item),
19	    0,
20	  );
21	  const premium = itemsTotal + PROCESSING_FEE;
22	  return { results: [{ premium }] };
23	};
24

1	import { describe, it, expect } from "vitest";
